module mux4to1 (
    input [1:0] sel,
    input [3:0] obf_data,
    output reg y
);

    always @(*) begin
        case (sel)
            2'b00: y = obf_data[0];
            2'b01: y = obf_data[1];
            2'b10: y = obf_data[2];
            2'b11: y = obf_data[3];
            default: y = 1'b0;
        endcase
    end
endmodule
